    EzReceiptRequest ir = new EzReceiptRequest();
    ir.setInvoiceNo(invoiceId);
    ir.setVoidReason("發票作廢");

    InvoiceTWResponse res=invoice.voidInvoice(ir);
    if(!res.isSuccess()) {
        out.println(res.getMessage());
        return;
    }

    e.setFieldValueByAttribute("twinvoice_status","1","已作廢");
    e.save(user,bundle);
    out.println("發票"+invoiceId+"作廢:"+res.getMessage());



